mapper.select:
SELECT t.id, t.user_id, t.category_id, t.amount, t.type, t.memo, t.`date`, c.name AS category_name, c.icon AS category_icon FROM `transaction` t LEFT JOIN category c ON c.id = t.category_id WHERE t.user_id = #{userId}
AND t.`date` >= #{startDate}
AND t.`date` <= #{endDate}
AND t.type = #{type}
AND t.category_id = #{categoryId}
ORDER BY t.`date` DESC, t.id DESC

mapper.update:
UPDATE `transaction`
SET category_id = #{categoryId},
    amount = #{amount},
    type = #{type},
    memo = #{memo},
    `date` = #{date}
WHERE id = #{id}    
  AND user_id = #{userId}

mapper.delete:
DELETE FROM `transaction`
WHERE id = #{id}
  AND user_id = #{userId}
